  ('fire-eq-tech-moex-00265', 'fire-eq-tech', 'fire-eq-tech-moex-112-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '某引擎試驗室設置有泡沫滅火設備，採高發泡放出口局部放射方式，依規定高發泡放出口之 泡沫水溶液放射量，防護面積每1平方公尺應在每分鐘X公升以上。又防護面積係指防護對 象外周線以高出防護對象物高度Y倍數值（該數值小於1公尺時，以1公尺計）所包圍之面 積。其中X+Y=？', '["5", "7", "9", "11"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:23+00:00", "source_pdf_sha1": "2a656458371a", "answer_pdf_sha1": "e41aac16b338", "source_family": "moex-gov-tw", "moex": {"exam_code": "112060", "c": "402", "s": "0810", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "水與化學系統消防安全設備概要", "year": "112", "exam_name": "112年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
